/**
 * AI 服务 - 主进程 IPC 处理器
 * 处理渲染进程发来的 AI 相关 IPC 调用
 */

import { IpcMain, BrowserWindow } from 'electron'
import axios, { AxiosError } from 'axios'
import fs from 'node:fs'
import path from 'node:path'
import os from 'node:os'
import { app } from 'electron'

// ─── 配置路径 ────────────────────────────────────────────────────────────────

function getSettingsPath(): string {
  return path.join(app.getPath('userData'), 'ai-settings.json')
}

// ─── 配置读写 ────────────────────────────────────────────────────────────────

interface AiSettings {
  deepseekApiKey?: string
  doubaoApiKey?: string
  [key: string]: string | undefined
}

function loadSettings(): AiSettings {
  const p = getSettingsPath()
  if (fs.existsSync(p)) {
    try {
      return JSON.parse(fs.readFileSync(p, 'utf-8'))
    } catch {
      return {}
    }
  }
  return {}
}

function saveSettings(settings: AiSettings): void {
  const p = getSettingsPath()
  fs.mkdirSync(path.dirname(p), { recursive: true })
  fs.writeFileSync(p, JSON.stringify(settings, null, 2), 'utf-8')
}

// ─── API 调用 ────────────────────────────────────────────────────────────────

interface CallOptions {
  model?: string
  systemPrompt?: string
  temperature?: number
  maxTokens?: number
  topP?: number
  presencePenalty?: number
  frequencyPenalty?: number
}

async function callAI(
  prompt: string,
  options: CallOptions = {}
): Promise<{ success: boolean; content?: string; reasoning?: string; error?: string }> {
  const { model = 'deepseek', systemPrompt, temperature = 0.7, maxTokens = 2000 } = options

  const apiKey = loadSettings()[`${model}ApiKey`]
    || process.env.DEEPSEEK_API_KEY
    || process.env.DOUBAO_API_KEY

  if (!apiKey) {
    return {
      success: false,
      error: `未配置 API Key。请先在设置中配置 ${model} 的 API Key。`,
    }
  }

  try {
    const isDeepSeek = model === 'deepseek' || model === 'deepseek-chat' || model === 'deepseek-reasoner'
    if (isDeepSeek) {
      const deepseekModel = model === 'deepseek-reasoner' ? 'deepseek-reasoner' : 'deepseek-chat'
      const response = await axios.post(
        'https://api.deepseek.com/v1/chat/completions',
        {
          model: deepseekModel,
          messages: [
            ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
            { role: 'user', content: prompt },
          ],
          temperature,
          max_tokens: maxTokens,
        },
        {
          headers: {
            Authorization: `Bearer ${apiKey}`,
            'Content-Type': 'application/json',
          },
          timeout: 60000,
        }
      )
      return { success: true, content: response.data.choices[0]?.message?.content || '' }
    }

    if (model === 'doubao-pro' || model === 'doubao-lite' || model === 'doubao-mini') {
      const endpoint = model === 'doubao-pro'
        ? 'https://ark.cn-beijing.volces.com/api/v3/chat/completions'
        : 'https://ark.cn-beijing.volces.com/api/v3/chat/completions'

      const doubaoModel = model === 'doubao-pro'
        ? 'doubao-pro-32k'
        : model === 'doubao-lite'
          ? 'doubao-lite-32k'
          : 'doubao-mini'

      const response = await axios.post(
        endpoint,
        {
          model: doubaoModel,
          messages: [
            ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
            { role: 'user', content: prompt },
          ],
          temperature,
          max_tokens: maxTokens,
        },
        {
          headers: {
            Authorization: `Bearer ${apiKey}`,
            'Content-Type': 'application/json',
          },
          timeout: 60000,
        }
      )
      return { success: true, content: response.data.choices[0]?.message?.content || '' }
    }

    return { success: false, error: `不支持的模型: ${model}` }
  } catch (err) {
    const axiosErr = err as AxiosError
    if (axiosErr.response) {
      return { success: false, error: `API 错误 ${axiosErr.response.status}: ${JSON.stringify(axiosErr.response.data)}` }
    }
    return { success: false, error: `请求失败: ${axiosErr.message}` }
  }
}

async function streamAI(
  prompt: string,
  options: CallOptions,
  sendChunk: (content: string, done: boolean, reasoning?: string) => void,
  sendError: (error: string) => void
): Promise<void> {
  const { model = 'deepseek', systemPrompt, temperature = 0.7, maxTokens = 2000 } = options

  const apiKey = loadSettings()[`${model}ApiKey`]
    || process.env.DEEPSEEK_API_KEY
    || process.env.DOUBAO_API_KEY

  if (!apiKey) {
    sendError(`未配置 API Key。请先在设置中配置 ${model} 的 API Key。`)
    sendChunk('', true)
    return
  }

  try {
    const isDeepSeek = model === 'deepseek' || model === 'deepseek-chat' || model === 'deepseek-reasoner'
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`,
    }

    const body: Record<string, unknown> = {
      model: isDeepSeek
        ? (model === 'deepseek-reasoner' ? 'deepseek-reasoner' : 'deepseek-chat')
        : 'doubao-pro-32k',
      messages: [
        ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
        { role: 'user', content: prompt },
      ],
      temperature,
      max_tokens: maxTokens,
    }

    // DeepSeek（实际也是火山引擎 Doubao 端）支持流式
    if (isDeepSeek) {
      body.stream = true

      const response = await axios.post(
        'https://api.deepseek.com/v1/chat/completions',
        body,
        {
          headers,
          responseType: 'stream',
          timeout: 120000,
        }
      )

      const stream = response.data as import('node:stream').Stream
      let buffer = ''

      await new Promise<void>((resolve, reject) => {
        stream.on('data', (chunk: Buffer) => {
          buffer += chunk.toString()
          const lines = buffer.split('\n')
          buffer = lines.pop() || ''

          for (const line of lines) {
            const trimmed = line.trim()
            if (!trimmed || trimmed === 'data: [DONE]') continue
            if (!trimmed.startsWith('data: ')) continue
            const data = trimmed.slice(6)
            try {
              const parsed = JSON.parse(data)
              const content = parsed.choices?.[0]?.delta?.content || ''
              const reasoning = parsed.choices?.[0]?.delta?.reasoning || ''
              if (content || reasoning) {
                sendChunk(content, false, reasoning)
              }
            } catch {}
          }
        })

        stream.on('end', () => {
          if (buffer.trim() && buffer.trim() !== '[DONE]') {
            try {
              const data = JSON.parse(buffer.slice(6))
              const content = data.choices?.[0]?.delta?.content || ''
              if (content) sendChunk(content, false)
            } catch {}
          }
          sendChunk('', true)
          resolve()
        })

        stream.on('error', (err: Error) => {
          sendError(err.message)
          sendChunk('', true)
          resolve()
        })
      })
    } else {
      // 非流式降级
      const result = await callAI(prompt, options)
      if (result.success) {
        sendChunk(result.content || '', false)
        sendChunk('', true)
      } else {
        sendError(result.error || '未知错误')
        sendChunk('', true)
      }
    }
  } catch (err) {
    const axiosErr = err as AxiosError
    sendError(axiosErr.message || '请求失败')
    sendChunk('', true)
  }
}

// ─── IPC 处理器 ──────────────────────────────────────────────────────────────

export function setupAiHandlers(ipcMain: IpcMain): void {
  // 保存 API Key
  ipcMain.handle('ai:saveApiKey', async (_event, service: string, apiKey: string) => {
    try {
      const settings = loadSettings()
      settings[`${service}ApiKey`] = apiKey
      saveSettings(settings)
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 检查是否已配置
  ipcMain.handle('ai:isConfigured', async (_event, service: string) => {
    const settings = loadSettings()
    const configured = !!(settings[`${service}ApiKey`] || process.env[`${service.toUpperCase()}_API_KEY`])
    return { success: true, configured }
  })

  // 获取已配置的服务列表
  ipcMain.handle('ai:getConfiguredServices', async () => {
    const settings = loadSettings()
    const services: string[] = []
    if (settings.deepseekApiKey || process.env.DEEPSEEK_API_KEY) services.push('deepseek')
    if (settings.doubaoApiKey || process.env.DOUBAO_API_KEY) services.push('doubao')
    return { success: true, services }
  })

  // AI 调用（非流式）
  ipcMain.handle('ai:call', async (_event, prompt: string, options?: CallOptions) => {
    return callAI(prompt, options || {})
  })

  // AI 流式调用
  ipcMain.handle('ai:stream', async (event, prompt: string, options?: CallOptions) => {
    const win = BrowserWindow.fromWebContents(event.sender)
    if (!win || win.isDestroyed()) return { success: false, error: '窗口已关闭' }

    await streamAI(
      prompt,
      options || {},
      (content, done, reasoning) => {
        if (!win.isDestroyed()) {
          win.webContents.send('ai:stream-chunk', { content, done, reasoning })
        }
      },
      (error) => {
        if (!win.isDestroyed()) {
          win.webContents.send('ai:stream-error', error)
        }
      }
    )

    return { success: true }
  })

  // 测试连接
  ipcMain.handle('ai:testConnection', async (_event, service: string) => {
    const testPrompt = '请回复"连接成功"，不需要其他内容。'
    const result = await callAI(testPrompt, { model: service, maxTokens: 50 })
    return { success: result.success, result: result.success, error: result.error }
  })

  // 保存设置
  ipcMain.handle('ai:saveSetting', async (_event, key: string, value: any) => {
    try {
      const settings = loadSettings()
      settings[key] = value
      saveSettings(settings)
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 读取设置
  ipcMain.handle('ai:getSetting', async (_event, key: string, defaultValue?: any) => {
    const settings = loadSettings()
    return { success: true, value: settings[key] ?? defaultValue }
  })
}

/**
 * YAML 服务 - 主进程 IPC 处理器
 * 提供 YAML 文件的安全读写，解析和序列化
 * 所有路径操作必须经过 validatePath 验证，防止目录遍历攻击
 */

import { IpcMain } from 'electron'
import fs from 'node:fs'
import path from 'node:path'
import yaml from 'js-yaml'

// ─── 路径验证（与 index.ts 保持一致） ───────────────────────────────────────

function validateYamlPath(requestedPath: string): { valid: boolean; resolvedPath?: string; error?: string } {
  // yamlService 只允许操作项目子目录下的 facts/ 目录
  //  Facts 目录固定在 {projectRoot}/facts/
  // 但由于 yamlService 不持有 projectRoot，需要由调用方（factsStore）保证传入合法路径
  // 这里做最后一道防线：禁止跨盘符访问和敏感路径
  const normalized = path.normalize(path.resolve(requestedPath))

  // 规范化路径分隔符，确保跨平台兼容（Windows 上 / 和 \ 需要统一）
  const normalizeSeparators = (p: string) => p.replace(/[\\/]/g, path.sep)
  const normalizedWithConsistentSeparators = normalizeSeparators(normalized)

  const sensitivePaths = [
    'C:\\Windows',
    'C:\\Program Files',
    '/etc',
    '/usr',
    '/root',
    '/home',
  ]

  for (const sensitive of sensitivePaths) {
    if (normalizedWithConsistentSeparators.toLowerCase().startsWith(normalizeSeparators(sensitive).toLowerCase())) {
      return { valid: false, error: `禁止访问系统路径: ${sensitive}` }
    }
  }

  return { valid: true, resolvedPath: normalized }
}

// ─── IPC 处理器 ──────────────────────────────────────────────────────────────

export function setupYamlHandlers(ipcMain: IpcMain): void {
  ipcMain.handle('yaml:read', async (_event, filePath: string): Promise<{ success: boolean; data?: any; error?: string }> => {
    try {
      const validation = validateYamlPath(filePath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }
      if (!fs.existsSync(validation.resolvedPath!)) {
        return { success: false, error: '文件不存在' }
      }
      const content = fs.readFileSync(validation.resolvedPath!, 'utf-8')
      const data = yaml.load(content)
      return { success: true, data }
    } catch (e: any) {
      return { success: false, error: `YAML 解析失败: ${e.message}` }
    }
  })

  ipcMain.handle('yaml:write', async (_event, filePath: string, data: any): Promise<{ success: boolean; error?: string }> => {
    try {
      const validation = validateYamlPath(filePath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }
      const dir = path.dirname(validation.resolvedPath!)
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true })
      }
      const yamlStr = yaml.dump(data)
      fs.writeFileSync(validation.resolvedPath!, yamlStr, 'utf-8')
      return { success: true }
    } catch (e: any) {
      return { success: false, error: `YAML 写入失败: ${e.message}` }
    }
  })
}

/**
 * Facts 持久化层
 * 通过 IPC 调用主进程的 yamlService，读写 facts/*.yaml 文件
 * 与命令行工具共用同一数据源
 */

export interface Fact {
  id: string
  type: 'power' | 'item' | 'relation' | 'foreshadow'
  subject: string
  object: string
  content: string
  chapterStart: number
  chapterEnd: number
  createdAt: number
}

class FactsStore {
  private projectRoot: string | null = null

  async setProjectRoot(root: string): Promise<void> {
    if (!root || typeof root !== 'string') {
      throw new Error('无效的项目根路径')
    }
    this.projectRoot = root
  }

  private factsDir(): string {
    if (!this.projectRoot) throw new Error('未设置项目根路径')
    return `${this.projectRoot}/facts`
  }

  // ─── 读取 facts（通过 IPC 调用主进程 js-yaml） ─────────────────────────────

  async loadCharactersFacts(): Promise<Record<string, unknown>> {
    try {
      const result = await window.electronAPI.yaml.read(`${this.factsDir()}/characters_facts.yaml`)
      if (result.success && result.data) return result.data as Record<string, unknown>
    } catch (e) {
      console.error('loadCharactersFacts 失败:', e)
    }
    return {}
  }

  async loadPlotFacts(): Promise<Record<string, unknown>> {
    try {
      const result = await window.electronAPI.yaml.read(`${this.factsDir()}/plot_facts.yaml`)
      if (result.success && result.data) return result.data as Record<string, unknown>
    } catch (e) {
      console.error('loadPlotFacts 失败:', e)
    }
    return {}
  }

  async loadSettingsFacts(): Promise<Record<string, unknown>> {
    try {
      const result = await window.electronAPI.yaml.read(`${this.factsDir()}/settings_facts.yaml`)
      if (result.success && result.data) return result.data as Record<string, unknown>
    } catch (e) {
      console.error('loadSettingsFacts 失败:', e)
    }
    return {}
  }

  // ─── 写入 facts（通过 IPC 调用主进程 js-yaml） ─────────────────────────────

  async appendFacts(facts: Array<{
    type: string
    subject: string
    object?: string
    content: string
    chapterStart: number
    chapterEnd: number
    confidence: number
  }>): Promise<{ success: boolean; error?: string }> {
    try {
      if (!this.projectRoot) {
        return { success: false, error: '未设置项目根路径' }
      }

      const charFacts = (await this.loadCharactersFacts()) as Record<string, Record<string, unknown>>
      const plotFacts = (await this.loadPlotFacts()) as Record<string, unknown>

      for (const fact of facts) {
        if (fact.type === 'power' || fact.type === 'item' || fact.type === 'relation') {
          if (!charFacts[fact.subject]) {
            charFacts[fact.subject] = {}
          }
          const char: Record<string, unknown> = charFacts[fact.subject]

          if (fact.type === 'power' && fact.content) {
            const abilities = (char['abilities'] as string[]) || []
            if (!abilities.includes(fact.content)) {
              abilities.push(fact.content)
              char['abilities'] = abilities
            }
          }
          if (fact.type === 'relation' && fact.object) {
            const relationships = (char['relationships'] as Record<string, string>) || {}
            relationships[fact.object] = fact.content
            char['relationships'] = relationships
          }
          if (fact.type === 'item' && fact.content) {
            const traits = (char['personality_traits'] as string[]) || []
            if (!traits.includes(fact.content)) {
              traits.push(fact.content)
              char['personality_traits'] = traits
            }
          }
        }

        if (fact.type === 'foreshadow') {
          const foreshadowList = (plotFacts['伏笔清单'] as Array<Record<string, unknown>>) || []
          const existing = foreshadowList.some(
            p => p['description'] === fact.content && p['setup_chapter'] === fact.chapterStart
          )
          if (!existing) {
            foreshadowList.push({
              id: `F${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
              description: fact.content,
              setup_chapter: fact.chapterStart,
              status: '待回收',
              related_characters: fact.subject ? [fact.subject] : [],
            })
            plotFacts['伏笔清单'] = foreshadowList
          }
        }
      }

      const charWriteResult = await window.electronAPI.yaml.write(`${this.factsDir()}/characters_facts.yaml`, charFacts)
      if (!charWriteResult.success) {
        throw new Error(`角色事实保存失败: ${charWriteResult.error}`)
      }
      const plotWriteResult = await window.electronAPI.yaml.write(`${this.factsDir()}/plot_facts.yaml`, plotFacts)
      if (!plotWriteResult.success) {
        throw new Error(`情节事实保存失败: ${plotWriteResult.error}`)
      }

      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  }

  // ─── 读取 facts 用于 UI 显示 ─────────────────────────────────────────────

  async getFacts(
    filters?: {
      type?: string
      subject?: string
      chapter?: number
    },
    projectRootOverride?: string | null
  ): Promise<Fact[]> {
    const effectiveRoot = projectRootOverride ?? this.projectRoot
    if (!effectiveRoot) {
      throw new Error('未设置项目根路径，请先打开小说项目')
    }
    const factsDir = `${effectiveRoot}/facts`
    try {
      // 直接用 effectiveRoot 读取，不走 this.projectRoot（可能未同步）
      const charResult = await window.electronAPI.yaml.read(`${factsDir}/characters_facts.yaml`)
      const charFacts = (charResult.success && charResult.data
        ? charResult.data as Record<string, Record<string, unknown>>
        : {}) as Record<string, Record<string, unknown>>
      const plotResult = await window.electronAPI.yaml.read(`${factsDir}/plot_facts.yaml`)
      const plotFacts = (plotResult.success && plotResult.data
        ? plotResult.data as Record<string, unknown>
        : {}) as Record<string, unknown>

      const results: Fact[] = []

      // 从 characters_facts.yaml 还原 facts
      for (const [charName, char] of Object.entries(charFacts)) {
        if (char.abilities) {
          for (const ability of (char.abilities as string[]) || []) {
            results.push({
              id: `power-${charName}-${ability}`.slice(0, 64),
              type: 'power',
              subject: charName,
              object: '',
              content: ability,
              chapterStart: 1,
              chapterEnd: 9999,
              createdAt: 0,
            })
          }
        }
        if (char.relationships) {
          for (const [other, rel] of Object.entries(char.relationships as Record<string, string>)) {
            results.push({
              id: `rel-${charName}-${other}`.slice(0, 64),
              type: 'relation',
              subject: charName,
              object: other,
              content: rel,
              chapterStart: 1,
              chapterEnd: 9999,
              createdAt: 0,
            })
          }
        }
      }

      // 从 plot_facts.yaml 还原伏笔
      if (plotFacts['伏笔清单']) {
        for (const fb of (plotFacts['伏笔清单'] as Array<Record<string, unknown>>)) {
          results.push({
            id: `fb-${fb['id']}` || `fb-${Date.now()}`,
            type: 'foreshadow',
            subject: ((fb['related_characters'] as string[] || [])[0]) || '',
            object: '',
            content: String(fb['description'] || ''),
            chapterStart: Number(fb['setup_chapter'] || 1),
            chapterEnd: Number(fb['setup_chapter'] || 1),
            createdAt: 0,
          })
        }
      }

      // 过滤
      let filtered = results
      if (filters?.type && filters.type !== 'all') {
        filtered = filtered.filter(f => f.type === filters.type)
      }
      if (filters?.subject) {
        filtered = filtered.filter(
          f => f.subject === filters.subject || f.object === filters.subject
        )
      }
      if (filters?.chapter) {
        filtered = filtered.filter(
          f => f.chapterStart <= filters.chapter! && f.chapterEnd >= filters.chapter!
        )
      }

      return filtered
    } catch (e) {
      console.error('读取 facts 失败:', e)
      return []
    }
  }
}

const factsStore = new FactsStore()
export default factsStore

